// // This module implements a 3-bit binary counter with an active high synchronous reset and a disable signal.
module binary_counter(
	input clk,
	input reset_n,
	input enable,
	output reg [2:0] count);

always @(posedge clk or negedge reset_n)
	if (!reset_n)
		count <= 0;
	else if (enable)
		count <= count + 1;

endmodule
